import{_ as d,o as a,c as l,ae as r}from"./chunks/framework.DAK3ioSj.js";const u=JSON.parse('{"title":"Skill 评测技术","description":"","frontmatter":{},"headers":[],"relativePath":"radar/category-04-evaluation.md","filePath":"radar/category-04-evaluation.md"}'),e={name:"radar/category-04-evaluation.md"};function i(o,t,h,n,s,b){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="skill-评测技术" tabindex="-1">Skill 评测技术 <a class="header-anchor" href="#skill-评测技术" aria-label="Permalink to &quot;Skill 评测技术&quot;">​</a></h1><blockquote><p><strong>版本</strong>: v1.0.0 <strong>创建日期</strong>: 2026-05-10 <strong>分类</strong>: Skill 生命周期 - 第四阶段 <strong>成熟度</strong>: 🟢 成熟期 | 综合评分: 0.73</p></blockquote><hr><h2 id="一、技术概述" tabindex="-1">一、技术概述 <a class="header-anchor" href="#一、技术概述" aria-label="Permalink to &quot;一、技术概述&quot;">​</a></h2><p><strong>Skill 评测</strong>是贯穿 Skill 全生命周期的量化评估与质量定级体系，核心目标是构建可量化、可复现的多维度指标，以客观数据衡量 Skill 好不好用、稳不稳定、安不安全、有没有价值。</p><hr><h2 id="二、核心技术领域" tabindex="-1">二、核心技术领域 <a class="header-anchor" href="#二、核心技术领域" aria-label="Permalink to &quot;二、核心技术领域&quot;">​</a></h2><h3 id="_2-1-多维评测" tabindex="-1">2.1 多维评测 <a class="header-anchor" href="#_2-1-多维评测" aria-label="Permalink to &quot;2.1 多维评测&quot;">​</a></h3><p>从多个维度评估 Skill 效果。</p><table tabindex="0"><thead><tr><th>指标</th><th>描述</th><th>成熟度</th></tr></thead><tbody><tr><td>准确率</td><td>任务完成度</td><td>🟢 成熟</td></tr><tr><td>Skill 召回率</td><td>正确选中目标 Skill 的比率</td><td>🟢 成熟</td></tr><tr><td>Token 消耗</td><td>单次调用 Token 消耗</td><td>🟢 成熟</td></tr><tr><td>执行时延</td><td>任务完成时间</td><td>🟢 成熟</td></tr><tr><td>CPSR</td><td>Cost-Per-Skill-Recall，每个召回的平均成本</td><td>🟡 成长期</td></tr></tbody></table><h3 id="_2-2-执行追溯" tabindex="-1">2.2 执行追溯 <a class="header-anchor" href="#_2-2-执行追溯" aria-label="Permalink to &quot;2.2 执行追溯&quot;">​</a></h3><p>记录每步操作，支持回溯分析。</p><table tabindex="0"><thead><tr><th>技术</th><th>描述</th><th>成熟度</th></tr></thead><tbody><tr><td>操作记录</td><td>记录推理、工具调用等</td><td>🟢 成熟</td></tr><tr><td>路径回溯</td><td>回溯执行路径</td><td>🟡 成长期</td></tr><tr><td>偏差检测</td><td>检测与预期的偏差</td><td>🟡 成长期</td></tr></tbody></table><h3 id="_2-3-归因分析" tabindex="-1">2.3 归因分析 <a class="header-anchor" href="#_2-3-归因分析" aria-label="Permalink to &quot;2.3 归因分析&quot;">​</a></h3><p>区分问题根因，指导优化方向。</p><table tabindex="0"><thead><tr><th>技术</th><th>描述</th><th>成熟度</th></tr></thead><tbody><tr><td>缺陷定位</td><td>定位 Skill 设计缺陷</td><td>🟡 成长期</td></tr><tr><td>根因分析</td><td>区分 Skill 设计与模型能力问题</td><td>🟡 成长期</td></tr><tr><td>优化建议</td><td>生成针对性优化建议</td><td>🟡 成长期</td></tr></tbody></table><h3 id="_2-4-安全审计" tabindex="-1">2.4 安全审计 <a class="header-anchor" href="#_2-4-安全审计" aria-label="Permalink to &quot;2.4 安全审计&quot;">​</a></h3><p>检测 Skill 中的安全漏洞。</p><table tabindex="0"><thead><tr><th>技术</th><th>描述</th><th>成熟度</th></tr></thead><tbody><tr><td>漏洞扫描</td><td>检测 Skill 中的安全漏洞</td><td>🟡 成长期</td></tr><tr><td>权限审计</td><td>检查权限授予合理性</td><td>🟡 成长期</td></tr><tr><td>数据泄露检测</td><td>检测敏感数据访问</td><td>🟡 成长期</td></tr></tbody></table><hr><h2 id="三、代表技术与项目" tabindex="-1">三、代表技术与项目 <a class="header-anchor" href="#三、代表技术与项目" aria-label="Permalink to &quot;三、代表技术与项目&quot;">​</a></h2><h3 id="_3-1-skill-insight" tabindex="-1">3.1 skill-insight <a class="header-anchor" href="#_3-1-skill-insight" aria-label="Permalink to &quot;3.1 skill-insight&quot;">​</a></h3><p>openEuler 社区推出的多维评测与执行追溯平台。</p><p><strong>核心能力</strong>：</p><ul><li>覆盖效果、效率、成本多维指标</li><li>实时生成执行流程图</li><li>智能归因分析</li></ul><p><strong>链接</strong>：<a href="https://atomgit.com/openeuler/witty-skill-insight" target="_blank" rel="noreferrer">AtomGit</a></p><h3 id="_3-2-skillsbench" tabindex="-1">3.2 SkillsBench <a class="header-anchor" href="#_3-2-skillsbench" aria-label="Permalink to &quot;3.2 SkillsBench&quot;">​</a></h3><p>衡量智能体技能在多样化任务中表现的基准测试。</p><p><strong>核心发现</strong>：</p><ul><li>人工精选的 Agent 技能能显著提升任务表现（平均 +16.2%）</li><li>模型无法可靠生成对自身有效的技能</li><li>技能设计应遵循&quot;少即是多&quot;原则（2-3 个技能效果最佳）</li></ul><h3 id="_3-3-skillprobe" tabindex="-1">3.3 SkillProbe <a class="header-anchor" href="#_3-3-skillprobe" aria-label="Permalink to &quot;3.3 SkillProbe&quot;">​</a></h3><p>用&quot;魔法&quot;打败&quot;魔法&quot;——用 Skill 审计 Skills。</p><p><strong>核心能力</strong>：</p><ul><li>安全漏洞检测</li><li>权限滥用检测</li><li>恶意行为识别</li></ul><hr><h2 id="四、技术成熟度分析" tabindex="-1">四、技术成熟度分析 <a class="header-anchor" href="#四、技术成熟度分析" aria-label="Permalink to &quot;四、技术成熟度分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>技术</th><th>技术成熟度</th><th>创新性</th><th>落地程度</th><th>生态活跃度</th><th>综合</th></tr></thead><tbody><tr><td>多维评测</td><td>0.85</td><td>0.75</td><td>0.80</td><td>0.70</td><td>0.78</td></tr><tr><td>执行追溯</td><td>0.75</td><td>0.70</td><td>0.70</td><td>0.65</td><td>0.71</td></tr><tr><td>归因分析</td><td>0.65</td><td>0.80</td><td>0.60</td><td>0.55</td><td>0.66</td></tr><tr><td>安全审计</td><td>0.65</td><td>0.70</td><td>0.55</td><td>0.50</td><td>0.61</td></tr><tr><td><strong>阶段综合</strong></td><td><strong>0.85</strong></td><td><strong>0.80</strong></td><td><strong>0.75</strong></td><td><strong>0.70</strong></td><td><strong>0.73</strong></td></tr></tbody></table><hr><h2 id="五、学习资源" tabindex="-1">五、学习资源 <a class="header-anchor" href="#五、学习资源" aria-label="Permalink to &quot;五、学习资源&quot;">​</a></h2><ul><li><a href="https://atomgit.com/openeuler/witty-skill-insight" target="_blank" rel="noreferrer">skill-insight 项目</a></li><li><a href="./../tech-blog/Agent Skills洞察与实践/【Agent Skills洞察与实践】11-SkillProbe：用&quot;魔法&quot;打败&quot;魔法&quot;——用Skill审计Skills.html">SkillProbe：用&quot;魔法&quot;打败&quot;魔法&quot;</a></li><li><a href="./../tech-blog/Agent Skills洞察与实践/【Agent Skills洞察与实践】05-集成Skills的单智能体，能否终结多智能体？.html">SkillsBench：衡量智能体技能表现的基准</a></li></ul>',40)])])}const c=d(e,[["render",i]]);export{u as __pageData,c as default};
